import uuid
import pytest
from datetime import datetime, timezone

def test_create_encounter_end_equals_start_boundary(api_client, auth_header, patient_id):
    ts = datetime(2024, 6, 1, 9, 0, 0, tzinfo=timezone.utc)
    payload = {
        "resourceType": "Encounter",
        "identifier": [{"value": str(uuid.uuid4())}],
        "status": "finished",
        "subject": {"reference": f"Patient/{patient_id}"},
        "period": {
            "start": ts.isoformat(),
            "end":   ts.isoformat()
        }
    }
    resp = api_client.post("/Encounter", json=payload, headers=auth_header)
    assert resp.status_code in (201, 422), (
        f"Unexpected status {resp.status_code} at end==start boundary"
    )
    body = resp.json()
    if resp.status_code == 201:
        assert body.get("resourceType") == "Encounter"
        assert "id" in body
    else:
        text = str(body).lower()
        assert "period" in text or "end" in text or "start" in text

import uuid
import pytest
from datetime import datetime, timezone, timedelta

def test_create_encounter_missing_subject_rejected(api_client, auth_header):
    start = datetime(2024, 6, 1, 9, 0, 0, tzinfo=timezone.utc)
    end   = start + timedelta(hours=1)
    payload = {
        "resourceType": "Encounter",
        "identifier": [{"value": str(uuid.uuid4())}],
        "status": "finished",
        "period": {
            "start": start.isoformat(),
            "end":   end.isoformat()
        }
    }
    resp = api_client.post("/Encounter", json=payload, headers=auth_header)
    assert resp.status_code in (400, 422), (
        f"Expected 400 or 422, got {resp.status_code}"
    )
    body = resp.json()
    assert body, "Expected non-empty error body"
